static const uint32_t g_blob_count = (uint32_t)(sizeof(g_blobs)/sizeof(g_blobs[0]));
void get_embedded_blobs(std::vector<AnchorPackBlob>& out) {
    out.clear();
    out.reserve(g_blob_count);
    for (uint32_t i = 0; i < g_blob_count; ++i) {
        AnchorPackBlob b;
        b.relpath_utf8 = g_blobs[i].relpath;
        b.comp_bytes_u8.assign(g_blobs[i].data, g_blobs[i].data + g_blobs[i].size);
        b.raw_size_u32 = g_blobs[i].raw_size;
        // No digests or hashing.
        out.push_back(std::move(b));
    }
}
